// ============================================================================
// Label Widget
// ============================================================================

struct Label : Widget {
    const wchar_t* text = L"";
    IDWriteTextFormat* text_format = nullptr;  // nullptr = use default g_text_format_body
    uint32_t color = Theme::TEXT_PRIMARY;

    // Text alignment (using DirectWrite constants)
    DWRITE_TEXT_ALIGNMENT text_align = DWRITE_TEXT_ALIGNMENT_LEADING;
    DWRITE_PARAGRAPH_ALIGNMENT para_align = DWRITE_PARAGRAPH_ALIGNMENT_CENTER;

    void measure(const LayoutConstraints& constraints) override {
        // Use provided format or default
        IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_body;
        if (!fmt || !g_dwrite_factory || !text || !text[0]) {
            preferred_width = padding_left + padding_right;
            preferred_height = 20.0f + padding_top + padding_bottom;  // Default height
            Widget::measure(constraints);
            return;
        }

        // Create text layout to measure
        IDWriteTextLayout* layout = nullptr;
        size_t text_len = wcslen(text);
        HRESULT hr = g_dwrite_factory->CreateTextLayout(
            text, static_cast<UINT32>(text_len), fmt,
            constraints.max_width - padding_left - padding_right,
            10000.0f,  // Large height for measurement
            &layout
        );

        if (SUCCEEDED(hr) && layout) {
            DWRITE_TEXT_METRICS metrics;
            layout->GetMetrics(&metrics);
            preferred_width = metrics.width + padding_left + padding_right;
            preferred_height = metrics.height + padding_top + padding_bottom;
            layout->Release();
        } else {
            preferred_width = 100.0f;  // Fallback
            preferred_height = 20.0f;
        }

        Widget::measure(constraints);
    }

    void render(RenderContext& ctx) override {
        if (!text || !text[0]) return;

        IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_body;
        if (!fmt) return;

        D2D1_RECT_F text_rect = D2D1::RectF(
            rect.x + padding_left,
            rect.y + padding_top,
            rect.x + rect.width - padding_right,
            rect.y + rect.height - padding_bottom
        );

        ctx.draw_text(text, wcslen(text), fmt, text_rect, color);
    }
};

// ============================================================================
// Button Widget
// ============================================================================

struct Button : Widget {
    const wchar_t* text = L"";
    IDWriteTextFormat* text_format = nullptr;  // nullptr = use default

    // Colors
    uint32_t bg_normal = Theme::ACCENT;
    uint32_t bg_hover = Theme::ACCENT_HOVER;
    uint32_t bg_pressed = Theme::ACCENT_PRESSED;
    uint32_t bg_disabled = 0xFF404040;
    uint32_t text_color = Theme::TEXT_PRIMARY;
    uint32_t text_disabled = Theme::TEXT_MUTED;

    float corner_radius = Theme::CORNER_RADIUS;

    // Callback
    void (*on_click)(Button* btn, void* user_data) = nullptr;
    void* user_data = nullptr;

    Button() {
        flags |= WidgetFlags::Focusable;
        // Buttons have default padding
        padding_left = 16.0f;
        padding_right = 16.0f;
        padding_top = 8.0f;
        padding_bottom = 8.0f;
    }

    void measure(const LayoutConstraints& constraints) override {
        // If width/height are explicitly set (Fixed mode), don't recalculate
        // This allows buttons to have explicit sizes set before measure
        bool need_width = (width_mode != SizeMode::Fixed);
        bool need_height = (height_mode != SizeMode::Fixed);

        if (!need_width && !need_height) {
            // Both dimensions are fixed, just apply constraints
            Widget::measure(constraints);
            return;
        }

        IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_button;
        if (!fmt || !g_dwrite_factory || !text || !text[0]) {
            if (need_width) preferred_width = 80.0f;
            if (need_height) preferred_height = 32.0f;
            Widget::measure(constraints);
            return;
        }

        // Measure text
        IDWriteTextLayout* layout = nullptr;
        size_t text_len = wcslen(text);
        HRESULT hr = g_dwrite_factory->CreateTextLayout(
            text, static_cast<UINT32>(text_len), fmt,
            1000.0f, 1000.0f, &layout
        );

        if (SUCCEEDED(hr) && layout) {
            DWRITE_TEXT_METRICS metrics;
            layout->GetMetrics(&metrics);
            if (need_width) preferred_width = metrics.width + padding_left + padding_right;
            if (need_height) preferred_height = metrics.height + padding_top + padding_bottom;
            layout->Release();
        } else {
            if (need_width) preferred_width = 80.0f;
            if (need_height) preferred_height = 32.0f;
        }

        Widget::measure(constraints);
    }

    bool on_mouse_enter() override {
        // Start hover animation
        if (!hover_anim) {
            hover_anim = g_widget_arena.create<HoverAnimation>();
        }
        hover_anim->target = 1.0f;
        set_dirty();
        return false;
    }

    bool on_mouse_leave() override {
        // End hover animation
        if (hover_anim) {
            hover_anim->target = 0.0f;
        }
        set_dirty();
        return false;
    }

    void render(RenderContext& ctx) override {
        float hover_t = get_hover_t();
        float scale = get_press_scale();

        // Determine background color based on state with smooth interpolation
        uint32_t bg = bg_normal;
        uint32_t fg = text_color;

        if (!(flags & WidgetFlags::Enabled)) {
            bg = bg_disabled;
            fg = text_disabled;
        } else if (flags & WidgetFlags::Pressed) {
            bg = bg_pressed;
        } else {
            // Interpolate between normal and hover based on animation
            bg = interpolate_color(bg_normal, bg_hover, hover_t);
        }

        // Calculate scaled rect for press animation
        float cx = rect.x + rect.width / 2.0f;
        float cy = rect.y + rect.height / 2.0f;
        float scaled_w = rect.width * scale;
        float scaled_h = rect.height * scale;

        D2D1_RECT_F bg_rect = D2D1::RectF(
            cx - scaled_w / 2.0f, cy - scaled_h / 2.0f,
            cx + scaled_w / 2.0f, cy + scaled_h / 2.0f
        );

        // Draw subtle shadow on hover (scales with hover animation)
        if (hover_t > 0.01f) {
            ctx.draw_shadow(bg_rect, corner_radius * scale,
                           Theme::SHADOW_BUTTON_OFFSET_Y * hover_t,
                           Theme::SHADOW_BUTTON_BLUR * hover_t,
                           Theme::SHADOW_BUTTON_OPACITY * hover_t);
        }

        // Draw background
        ctx.fill_rounded_rect(bg_rect, corner_radius * scale, bg);

        // Draw focus ring only when keyboard focused (Tab navigation)
        if (flags & WidgetFlags::KeyboardFocused) {
            ctx.draw_focus_ring(bg_rect, corner_radius * scale);
        }

        // Draw text (centered in scaled rect)
        if (text && text[0]) {
            IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_button;
            if (fmt) {
                D2D1_RECT_F text_rect = D2D1::RectF(
                    bg_rect.left + padding_left * scale,
                    bg_rect.top + padding_top * scale,
                    bg_rect.right - padding_right * scale,
                    bg_rect.bottom - padding_bottom * scale
                );
                ctx.draw_text(text, wcslen(text), fmt, text_rect, fg);
            }
        }
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;

        // Activate button with Enter or Space when focused
        if ((vk == VK_RETURN || vk == VK_SPACE) && (flags & WidgetFlags::Enabled)) {
            if (on_click) {
                on_click(this, user_data);
            }
            return true;
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        // Start press animation
        if (!press_anim) {
            press_anim = g_widget_arena.create<PressAnimation>();
        }
        press_anim->target = Theme::BUTTON_PRESS_SCALE;
        set_dirty();
        return true;  // Consume the event
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        // End press animation
        if (press_anim) {
            press_anim->target = 1.0f;
        }
        set_dirty();
        // Fire click callback if still hovered (mouse released over button)
        if ((flags & WidgetFlags::Hovered) && (flags & WidgetFlags::Enabled)) {
            if (on_click) {
                on_click(this, user_data);
            }
        }
        return true;
    }
};

// ============================================================================
// TextInput Undo System
// ============================================================================

struct TextInputUndoEntry {
    wchar_t* text = nullptr;        // Heap-allocated snapshot
    size_t text_len = 0;
    size_t cursor_pos = 0;
    size_t selection_start = 0;
    size_t selection_end = 0;

    ~TextInputUndoEntry() {
        if (text) {
            delete[] text;
            text = nullptr;
        }
    }

    void store(const wchar_t* src, size_t len, size_t cursor, size_t sel_start, size_t sel_end) {
        if (text) delete[] text;
        text = new wchar_t[len + 1];
        memcpy(text, src, (len + 1) * sizeof(wchar_t));
        text_len = len;
        cursor_pos = cursor;
        selection_start = sel_start;
        selection_end = sel_end;
    }

    void restore(wchar_t* dst, size_t* len, size_t* cursor, size_t* sel_start, size_t* sel_end) const {
        if (!text) return;
        memcpy(dst, text, (text_len + 1) * sizeof(wchar_t));
        *len = text_len;
        *cursor = cursor_pos;
        *sel_start = selection_start;
        *sel_end = selection_end;
    }
};

struct TextInputUndoStack {
    static constexpr size_t MAX_LEVELS = 50;
    TextInputUndoEntry entries[MAX_LEVELS];
    size_t count = 0;           // Number of valid entries
    size_t current = 0;         // Current position in history (for redo)
    int64_t last_action_time = 0;
    bool can_coalesce = false;  // Merge sequential single-char typing

    void push(const wchar_t* text, size_t len, size_t cursor, size_t sel_start, size_t sel_end) {
        int64_t now = GetTickCount64();

        // Typing coalescing: merge sequential single-char insertions within 1
        // second. Guarded with `current > 0` because if current==0 the only
        // existing entry is the initial snapshot — overwriting it would make
        // Ctrl+Z unable to return to that state.
        if (can_coalesce && current > 0 && (now - last_action_time) < 1000) {
            // Update current entry instead of creating new
            size_t idx = (current - 1) % MAX_LEVELS;
            entries[idx].store(text, len, cursor, sel_start, sel_end);
            last_action_time = now;
            return;
        }

        // Truncate redo history when new action is taken
        count = current;

        // Store new entry
        size_t idx = count % MAX_LEVELS;
        entries[idx].store(text, len, cursor, sel_start, sel_end);

        count++;
        if (count > MAX_LEVELS) count = MAX_LEVELS;
        current = count;

        last_action_time = now;
        can_coalesce = false;
    }

    bool undo(wchar_t* text, size_t* len, size_t* cursor, size_t* sel_start, size_t* sel_end) {
        if (current == 0) return false;

        current--;
        size_t idx = current % MAX_LEVELS;
        entries[idx].restore(text, len, cursor, sel_start, sel_end);

        can_coalesce = false;
        return true;
    }

    bool redo(wchar_t* text, size_t* len, size_t* cursor, size_t* sel_start, size_t* sel_end) {
        if (current >= count) return false;

        size_t idx = current % MAX_LEVELS;
        entries[idx].restore(text, len, cursor, sel_start, sel_end);
        current++;

        can_coalesce = false;
        return true;
    }

    bool can_undo() const { return current > 0; }
    bool can_redo() const { return current < count; }

    void enable_coalescing() { can_coalesce = true; }
    void disable_coalescing() { can_coalesce = false; }

    void clear() {
        for (size_t i = 0; i < MAX_LEVELS; i++) {
            if (entries[i].text) {
                delete[] entries[i].text;
                entries[i].text = nullptr;
            }
        }
        count = 0;
        current = 0;
        can_coalesce = false;
    }
};

// ============================================================================
// TextInput Widget
// ============================================================================

struct TextInput : Widget {
    wchar_t text[1024] = {};
    size_t text_len = 0;
    size_t cursor_pos = 0;
    size_t selection_start = 0;  // Same as cursor when no selection
    size_t selection_end = 0;

    const wchar_t* placeholder = L"";
    IDWriteTextFormat* text_format = nullptr;  // nullptr = use default

    // Appearance
    uint32_t bg_color = 0xFF1E1E1E;
    uint32_t border_color = 0xFF3C3C3C;
    uint32_t border_focus = Theme::ACCENT;
    uint32_t text_color = Theme::TEXT_PRIMARY;
    uint32_t placeholder_color = Theme::TEXT_MUTED;
    uint32_t selection_color = 0x400078D4;  // Semi-transparent accent
    uint32_t composition_underline_color = Theme::ACCENT;  // IME composition underline
    float corner_radius = 4.0f;
    float border_width = 1.0f;

    bool password_mode = false;
    bool multiline = false;  // For future use

    // TSF (Text Services Framework) for IME support
    TsfTextStore* tsf_store = nullptr;

    // Callbacks
    void (*on_change)(TextInput* input, void* user_data) = nullptr;
    void (*on_submit)(TextInput* input, void* user_data) = nullptr;
    void* user_data = nullptr;

    // === Horizontal Scrolling ===
    float scroll_offset = 0.0f;           // Pixels scrolled from left
    float content_width = 0.0f;           // Total text width (cached)
    bool content_width_dirty = true;      // Recalculate on text change

    // === Cursor Animation ===
    float cursor_opacity = 1.0f;          // 0.0-1.0 for smooth fade blink
    float cursor_blink_timer = 0.0f;      // Time since last cursor activity
    float cursor_blink_pause_timer = 0.0f; // Pause blink after cursor moves (seconds)
    float cursor_target_x = 0.0f;         // Target position (animated)
    float cursor_current_x = 0.0f;        // Current interpolated position
    bool cursor_x_initialized = false;    // First-time init flag

    // === Selection Animation ===
    float sel_anim_start_x = 0.0f;        // Animated selection start
    float sel_anim_end_x = 0.0f;          // Animated selection end
    float sel_target_start_x = 0.0f;      // Target selection start
    float sel_target_end_x = 0.0f;        // Target selection end

    // === Drag Selection State ===
    bool is_dragging = false;             // Mouse drag in progress
    size_t drag_anchor_pos = 0;           // Where drag started

    // === Multi-Click Detection ===
    int64_t last_click_time = 0;          // Timestamp of last click
    float last_click_x = 0.0f;            // Position of last click
    int click_count = 0;                  // 1=single, 2=double, 3=triple

    // === Undo/Redo ===
    TextInputUndoStack* undo_stack = nullptr;  // Lazily allocated

    // === Focus Animation ===
    HoverAnimation* focus_anim = nullptr;      // Border color transition

    // === Error State ===
    float error_shake_offset = 0.0f;      // Horizontal shake displacement
    float error_shake_timer = 0.0f;       // Duration remaining
    bool has_error = false;               // Show error border

    // === Animation scheduler guards ===
    // Each self-managed animation needs its own guard so the render loop
    // is kept alive while it runs and released when it settles.
    AnimGuard cursor_move_guard;
    AnimGuard cursor_blink_guard;
    AnimGuard selection_guard;
    AnimGuard shake_guard;

    TextInput() {
        flags |= WidgetFlags::Focusable | WidgetFlags::CapturesMouse;
        padding_left = 8.0f;
        padding_right = 8.0f;
        padding_top = 6.0f;
        padding_bottom = 6.0f;
        preferred_height = 32.0f;

        // Create TSF text store for IME support
        tsf_store = tsf_create_text_store(this);
    }

    ~TextInput() {
        // Clean up TSF store before widget is destroyed
        if (tsf_store) {
            tsf_destroy_text_store(tsf_store);
            tsf_store = nullptr;
        }
        // Cancel focus_anim's scheduler registration (base ~Widget only knows
        // about hover_anim/press_anim — focus_anim is TextInput-specific).
        if (focus_anim) {
            focus_anim->cancel();
        }
        // AnimGuard destructors handle their own scheduler cleanup.

        // Free heap-allocated undo stack (lazily allocated via 'new')
        if (undo_stack) {
            delete undo_stack;
            undo_stack = nullptr;
        }
    }

    void measure(const LayoutConstraints& constraints) override {
        // Fixed height for single-line input (unless explicitly set to Fixed mode)
        if (!multiline && height_mode != SizeMode::Fixed) {
            preferred_height = 32.0f;
        }
        Widget::measure(constraints);
    }

    // Animation tick - called every frame for smooth animations
    void tick(float dt) override {
        Widget::tick(dt);  // Base class hover animations
        bool needs_redraw = false;

        // === Cursor Position Animation ===
        bool cursor_is_moving = fabsf(cursor_current_x - cursor_target_x) > 0.5f;
        if (cursor_is_moving) {
            cursor_move_guard.start();
            float speed = 1000.0f / TextInputTheme::CURSOR_MOVE_MS;
            float delta = cursor_target_x - cursor_current_x;
            cursor_current_x += delta * fminf(1.0f, speed * dt);
            needs_redraw = true;
        } else {
            cursor_current_x = cursor_target_x;
            cursor_move_guard.stop();
        }

        // === Cursor Blink Animation ===
        // Only blink when focused, not moving, and pause timer has expired
        bool blink_active = false;
        if (flags & WidgetFlags::Focused) {
            // Decrement pause timer
            if (cursor_blink_pause_timer > 0.0f) {
                cursor_blink_pause_timer -= dt;
                // Keep cursor fully visible during pause
                cursor_opacity = 1.0f;
                needs_redraw = true;
                blink_active = true;
            } else if (cursor_is_moving) {
                // Cursor is animating - keep fully visible, don't run blink timer
                cursor_opacity = 1.0f;
                cursor_blink_timer = 0.0f;
                needs_redraw = true;
            } else {
                // Normal blink animation
                cursor_blink_timer += dt;
                float period = TextInputTheme::CURSOR_BLINK_PERIOD_MS / 1000.0f;
                float fade_time = TextInputTheme::CURSOR_FADE_MS / 1000.0f;
                float phase = fmodf(cursor_blink_timer, period);
                float half_period = period / 2.0f;

                float new_opacity;
                if (phase < fade_time) {
                    // Fading out
                    new_opacity = 1.0f - Easing::ease_out_quad(phase / fade_time);
                } else if (phase < half_period) {
                    // Fully invisible
                    new_opacity = 0.0f;
                } else if (phase < half_period + fade_time) {
                    // Fading in
                    new_opacity = Easing::ease_out_quad((phase - half_period) / fade_time);
                } else {
                    // Fully visible
                    new_opacity = 1.0f;
                }

                if (fabsf(new_opacity - cursor_opacity) > 0.01f) {
                    cursor_opacity = new_opacity;
                    needs_redraw = true;
                }
                // Blink runs continuously while focused — keep the render loop
                // alive so the next frame ticks back in here.
                blink_active = true;
            }
        }
        if (blink_active) cursor_blink_guard.start();
        else cursor_blink_guard.stop();

        // === Selection Animation ===
        bool sel_animating = false;
        if (fabsf(sel_anim_start_x - sel_target_start_x) > 0.5f) {
            float speed = 1000.0f / TextInputTheme::SELECTION_ANIM_MS;
            float delta = sel_target_start_x - sel_anim_start_x;
            sel_anim_start_x += delta * fminf(1.0f, speed * dt);
            sel_animating = true;
        } else {
            sel_anim_start_x = sel_target_start_x;
        }
        if (fabsf(sel_anim_end_x - sel_target_end_x) > 0.5f) {
            float speed = 1000.0f / TextInputTheme::SELECTION_ANIM_MS;
            float delta = sel_target_end_x - sel_anim_end_x;
            sel_anim_end_x += delta * fminf(1.0f, speed * dt);
            sel_animating = true;
        } else {
            sel_anim_end_x = sel_target_end_x;
        }
        if (sel_animating) {
            selection_guard.start();
            needs_redraw = true;
        } else {
            selection_guard.stop();
        }

        // === Focus Animation ===
        if (focus_anim && focus_anim->update(dt, TextInputTheme::FOCUS_TRANSITION_MS)) {
            needs_redraw = true;
        }

        // === Error Shake Animation ===
        if (error_shake_timer > 0.0f) {
            shake_guard.start();
            error_shake_timer -= dt;
            if (error_shake_timer > 0.0f) {
                float t = error_shake_timer / (TextInputTheme::SHAKE_DURATION_MS / 1000.0f);
                float damping = t * t;  // Quadratic decay
                error_shake_offset = sinf(error_shake_timer * TextInputTheme::SHAKE_FREQUENCY * 2.0f * 3.14159f)
                                   * TextInputTheme::SHAKE_AMPLITUDE * damping;
            } else {
                error_shake_offset = 0.0f;
                error_shake_timer = 0.0f;
                shake_guard.stop();
            }
            needs_redraw = true;
        } else {
            shake_guard.stop();
        }

        if (needs_redraw) {
            set_dirty();
        }
    }

    void render(RenderContext& ctx) override {
        // Apply error shake offset
        float shake_x = error_shake_offset;
        D2D1_RECT_F bg_rect = D2D1::RectF(
            rect.x + shake_x, rect.y,
            rect.x + rect.width + shake_x, rect.y + rect.height
        );

        // Background
        ctx.fill_rounded_rect(bg_rect, corner_radius, bg_color);

        // Border - show focus, hover, or default state with animation
        uint32_t border = border_color;
        if (has_error) {
            border = TextInputTheme::BORDER_ERROR;
        } else if (focus_anim) {
            // Animated transition between states
            float focus_t = focus_anim->eased();
            if (flags & WidgetFlags::Focused) {
                border = interpolate_color(border_color, border_focus, focus_t);
            } else if (flags & WidgetFlags::Hovered) {
                border = interpolate_color(border_color, TextInputTheme::BORDER_HOVER, focus_t);
            } else {
                // Animating away from focus/hover
                border = interpolate_color(border_focus, border_color, 1.0f - focus_t);
            }
        } else {
            // No animation active - use static colors
            if (flags & WidgetFlags::Focused) {
                border = border_focus;
            } else if (flags & WidgetFlags::Hovered) {
                border = TextInputTheme::BORDER_HOVER;
            }
        }
        ctx.brush->SetColor(color_from_argb(border));
        D2D1_ROUNDED_RECT rr = { bg_rect, corner_radius, corner_radius };
        ctx.target->DrawRoundedRectangle(rr, ctx.brush, border_width);

        IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_body;
        if (!fmt) return;

        // Content area (with shake offset)
        D2D1_RECT_F content_rect = D2D1::RectF(
            rect.x + padding_left + shake_x,
            rect.y + padding_top,
            rect.x + rect.width - padding_right + shake_x,
            rect.y + rect.height - padding_bottom
        );

        // Push clip
        ctx.push_clip(content_rect);

        // Calculate scroll-adjusted content rect for text
        D2D1_RECT_F scrolled_rect = content_rect;
        scrolled_rect.left -= scroll_offset;
        scrolled_rect.right += 1000.0f;  // Allow text to extend beyond clip

        // Draw selection highlight if focused and has selection
        if ((flags & WidgetFlags::Focused) && selection_start != selection_end && text_len > 0) {
            render_selection(ctx, fmt, content_rect);
        }

        // Draw text or placeholder
        if (text_len > 0) {
            const wchar_t* display_text = text;
            wchar_t dots[1024];

            // Draw dots for password (but show real text during composition for IME preview)
            bool in_composition = tsf_store && tsf_is_composing(tsf_store);
            if (password_mode && !in_composition) {
                for (size_t i = 0; i < text_len && i < 1023; i++) {
                    dots[i] = L'\x2022';  // Bullet character
                }
                dots[text_len] = L'\0';
                display_text = dots;
            }

            // Create text layout with NO_WRAP to prevent wrapping for long text
            IDWriteTextLayout* layout = nullptr;
            HRESULT hr = g_dwrite_factory->CreateTextLayout(
                display_text, static_cast<UINT32>(text_len), fmt,
                100000.0f,  // Very large max width to prevent wrapping
                content_rect.bottom - content_rect.top,
                &layout);
            if (SUCCEEDED(hr) && layout) {
                layout->SetWordWrapping(DWRITE_WORD_WRAPPING_NO_WRAP);
                ctx.brush->SetColor(color_from_argb(text_color));
                ctx.target->DrawTextLayout(
                    D2D1::Point2F(scrolled_rect.left, content_rect.top),
                    layout, ctx.brush);
                layout->Release();
            }

            // Draw composition underline for IME input
            if (tsf_store && tsf_is_composing(tsf_store)) {
                render_composition_underline(ctx, fmt, content_rect);
            }
        } else if (placeholder && placeholder[0]) {
            ctx.draw_text(placeholder, wcslen(placeholder), fmt, content_rect, placeholder_color);
        }

        // Draw cursor if focused
        if (flags & WidgetFlags::Focused) {
            render_cursor(ctx, fmt, content_rect);
        }

        ctx.pop_clip();
    }

    void render_selection(RenderContext& ctx, IDWriteTextFormat* fmt, const D2D1_RECT_F& content_rect) {
        if (!g_dwrite_factory) return;

        // Use animated selection bounds
        float start_x = sel_anim_start_x - scroll_offset + content_rect.left;
        float end_x = sel_anim_end_x - scroll_offset + content_rect.left;

        // Ensure start < end for drawing
        if (start_x > end_x) {
            float tmp = start_x;
            start_x = end_x;
            end_x = tmp;
        }

        // Clamp to visible content area
        start_x = fmaxf(start_x, content_rect.left);
        end_x = fminf(end_x, content_rect.right);

        if (end_x > start_x) {
            D2D1_RECT_F sel_rect = D2D1::RectF(start_x, content_rect.top, end_x, content_rect.bottom);
            ctx.fill_rect(sel_rect, selection_color);
        }
        (void)fmt;  // Not needed with animated positions
    }

    void render_cursor(RenderContext& ctx, IDWriteTextFormat* fmt, const D2D1_RECT_F& content_rect) {
        (void)fmt;  // Not needed with animated position

        // Skip if cursor is fully transparent
        if (cursor_opacity < 0.01f) return;

        // Use animated cursor position, adjusted for scroll
        float cursor_x = cursor_current_x - scroll_offset + content_rect.left;

        // Skip if cursor is outside visible area
        if (cursor_x < content_rect.left - 1.0f || cursor_x > content_rect.right + 1.0f) return;

        // Apply cursor opacity to text color
        uint32_t cursor_color = text_color;
        uint8_t alpha = static_cast<uint8_t>(((cursor_color >> 24) & 0xFF) * cursor_opacity);
        cursor_color = (alpha << 24) | (cursor_color & 0x00FFFFFF);

        // Draw cursor line
        ctx.draw_line(cursor_x, content_rect.top + 2.0f, cursor_x, content_rect.bottom - 2.0f, cursor_color, 1.0f);
    }

    void render_composition_underline(RenderContext& ctx, IDWriteTextFormat* fmt, const D2D1_RECT_F& content_rect) {
        if (!g_dwrite_factory || !tsf_store) return;

        size_t comp_start, comp_end;
        tsf_get_composition_range(tsf_store, &comp_start, &comp_end);

        if (comp_start >= comp_end || comp_end > text_len) return;

        // Create text layout to get positions
        IDWriteTextLayout* layout = nullptr;
        g_dwrite_factory->CreateTextLayout(
            text, static_cast<UINT32>(text_len), fmt,
            content_rect.right - content_rect.left,
            content_rect.bottom - content_rect.top,
            &layout
        );

        if (layout) {
            DWRITE_HIT_TEST_METRICS metrics;
            float x1, y1, x2, y2;

            // Get start position
            layout->HitTestTextPosition(static_cast<UINT32>(comp_start), FALSE, &x1, &y1, &metrics);

            // Get end position
            layout->HitTestTextPosition(static_cast<UINT32>(comp_end), FALSE, &x2, &y2, &metrics);

            // Draw underline at baseline
            float underline_y = content_rect.bottom - 4.0f;
            ctx.draw_line(
                content_rect.left + x1, underline_y,
                content_rect.left + x2, underline_y,
                composition_underline_color, 2.0f
            );

            layout->Release();
        }
    }

    bool on_focus() override {
        // Set TSF focus for IME support
        if (tsf_store) {
            tsf_set_focus(tsf_store);
        }

        // Start focus animation
        if (!focus_anim) {
            focus_anim = g_widget_arena.create<HoverAnimation>();
        }
        focus_anim->target = 1.0f;

        // Reset cursor blink
        reset_cursor_blink();

        // Initialize cursor position if needed
        if (!cursor_x_initialized) {
            cursor_target_x = get_cursor_x_in_text();
            cursor_current_x = cursor_target_x;
            cursor_x_initialized = true;
        }

        return true;
    }

    bool on_blur() override {
        // Clear TSF focus
        if (tsf_store) {
            tsf_clear_focus(tsf_store);
        }
        // Clear selection on blur
        selection_start = cursor_pos;
        selection_end = cursor_pos;

        // Stop dragging
        is_dragging = false;

        // Start blur animation
        if (focus_anim) {
            focus_anim->target = 0.0f;
        }

        return true;
    }

    bool wants_arrow_navigation() const override {
        // TextInput handles arrow keys internally for cursor movement
        return true;
    }

    bool on_escape() override {
        // If there's a selection, clear it (consume escape)
        if (selection_start != selection_end) {
            selection_start = cursor_pos;
            selection_end = cursor_pos;
            return true;  // Consumed: cleared selection
        }
        // No selection, let escape bubble up (blur or exit focus group)
        return false;
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)alt;

        switch (vk) {
            case VK_LEFT:
                if (cursor_pos > 0) {
                    if (ctrl) {
                        // Move to previous word
                        cursor_pos = find_word_start(cursor_pos - 1);
                    } else {
                        cursor_pos--;
                    }
                    if (!shift) {
                        selection_start = selection_end = cursor_pos;
                    } else {
                        selection_end = cursor_pos;
                    }
                    update_cursor_and_selection_targets();
                    reset_cursor_blink();
                }
                return true;

            case VK_RIGHT:
                if (cursor_pos < text_len) {
                    if (ctrl) {
                        // Move to next word
                        cursor_pos = find_word_end(cursor_pos);
                    } else {
                        cursor_pos++;
                    }
                    if (!shift) {
                        selection_start = selection_end = cursor_pos;
                    } else {
                        selection_end = cursor_pos;
                    }
                    update_cursor_and_selection_targets();
                    reset_cursor_blink();
                }
                return true;

            case VK_HOME:
                cursor_pos = 0;
                if (!shift) {
                    selection_start = selection_end = cursor_pos;
                } else {
                    selection_end = cursor_pos;
                }
                update_cursor_and_selection_targets();
                reset_cursor_blink();
                return true;

            case VK_END:
                cursor_pos = text_len;
                if (!shift) {
                    selection_start = selection_end = cursor_pos;
                } else {
                    selection_end = cursor_pos;
                }
                update_cursor_and_selection_targets();
                reset_cursor_blink();
                return true;

            case VK_BACK:
                if (selection_start != selection_end) {
                    push_undo_state();
                    delete_selection();
                } else if (cursor_pos > 0) {
                    push_undo_state();
                    if (ctrl) {
                        // Ctrl+Backspace: delete word before cursor
                        size_t word_start = find_word_start(cursor_pos - 1);
                        size_t chars_to_delete = cursor_pos - word_start;
                        memmove(&text[word_start], &text[cursor_pos], (text_len - cursor_pos + 1) * sizeof(wchar_t));
                        cursor_pos = word_start;
                        text_len -= chars_to_delete;
                    } else {
                        // Regular Backspace: delete single character
                        memmove(&text[cursor_pos - 1], &text[cursor_pos], (text_len - cursor_pos + 1) * sizeof(wchar_t));
                        cursor_pos--;
                        text_len--;
                    }
                    selection_start = selection_end = cursor_pos;
                    content_width_dirty = true;
                    update_cursor_and_selection_targets();
                    reset_cursor_blink();
                    notify_change();
                }
                return true;

            case VK_DELETE:
                if (selection_start != selection_end) {
                    push_undo_state();
                    delete_selection();
                } else if (cursor_pos < text_len) {
                    push_undo_state();
                    if (ctrl) {
                        // Ctrl+Delete: delete word after cursor
                        size_t word_end = find_word_end(cursor_pos);
                        size_t chars_to_delete = word_end - cursor_pos;
                        memmove(&text[cursor_pos], &text[word_end], (text_len - word_end + 1) * sizeof(wchar_t));
                        text_len -= chars_to_delete;
                    } else {
                        memmove(&text[cursor_pos], &text[cursor_pos + 1], (text_len - cursor_pos) * sizeof(wchar_t));
                        text_len--;
                    }
                    content_width_dirty = true;
                    update_cursor_and_selection_targets();
                    notify_change();
                }
                return true;

            case VK_RETURN:
                if (!multiline && on_submit) {
                    on_submit(this, user_data);
                }
                return true;

            case 'A':
                if (ctrl) {
                    // Select all
                    select_all();
                    return true;
                }
                break;

            case 'C':
                if (ctrl) {
                    copy_to_clipboard();
                    return true;
                }
                break;

            case 'V':
                if (ctrl) {
                    push_undo_state();
                    paste_from_clipboard();
                    return true;
                }
                break;

            case 'X':
                if (ctrl) {
                    push_undo_state();
                    copy_to_clipboard();
                    delete_selection();
                    return true;
                }
                break;

            case 'Z':
                if (ctrl) {
                    if (shift) {
                        // Ctrl+Shift+Z: Redo
                        redo();
                    } else {
                        // Ctrl+Z: Undo
                        undo();
                    }
                    return true;
                }
                break;

            case 'Y':
                if (ctrl) {
                    // Ctrl+Y: Redo
                    redo();
                    return true;
                }
                break;
        }

        return false;
    }

    bool on_char(wchar_t ch) override {
        // Skip if TSF is handling composition (IME input)
        if (tsf_store && tsf_is_composing(tsf_store)) {
            return true;  // TSF handles this through SetText
        }

        // Ignore control characters (Tab only allowed in multiline mode)
        if (ch < 32 && (ch != L'\t' || !multiline)) return false;
        if (ch == 127) return false;  // DEL

        // Push undo state before modification
        push_undo_state();

        // Delete selection first
        if (selection_start != selection_end) {
            delete_selection();
        }

        // Insert character
        if (text_len < 1022) {
            memmove(&text[cursor_pos + 1], &text[cursor_pos], (text_len - cursor_pos + 1) * sizeof(wchar_t));
            text[cursor_pos] = ch;
            cursor_pos++;
            text_len++;
            selection_start = selection_end = cursor_pos;
            content_width_dirty = true;
            update_cursor_and_selection_targets();
            reset_cursor_blink();
            enable_undo_coalescing();  // Allow merging sequential typing
            notify_change();
        }

        return true;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)y;
        if (button != 0) return false;  // Only handle left button

        // x is already relative to widget rect (EventDispatcher subtracts rect.x)
        // Convert to text-local coordinates (relative to content area, accounting for scroll)
        float local_x = x - padding_left + scroll_offset;

        // Multi-click detection
        int64_t now = GetTickCount64();
        float click_dist = fabsf(local_x - last_click_x);
        int64_t click_time = now - last_click_time;

        if (click_time < static_cast<int64_t>(TextInputTheme::DOUBLE_CLICK_MS) &&
            click_dist < TextInputTheme::DOUBLE_CLICK_DIST) {
            click_count = (click_count % 3) + 1;  // Cycle 1->2->3->1
        } else {
            click_count = 1;
        }
        last_click_time = now;
        last_click_x = local_x;

        // Check for Shift+Click to extend selection
        bool shift_held = (GetKeyState(VK_SHIFT) & 0x8000) != 0;

        size_t click_pos = get_char_index_at(x);

        if (click_count == 1) {
            if (shift_held) {
                // Shift+click: create/extend selection from anchor to click
                // If no selection exists, use current cursor as anchor
                if (selection_start == selection_end) {
                    selection_start = cursor_pos;
                }
                selection_end = click_pos;
                cursor_pos = click_pos;
                // Don't start drag - shift+click is a one-shot operation
            } else {
                // Single click: position cursor and start drag
                cursor_pos = click_pos;
                selection_start = selection_end = cursor_pos;
                drag_anchor_pos = cursor_pos;
                is_dragging = true;
            }
        } else if (click_count == 2) {
            // Double-click: select word
            select_word_at(click_pos);
            drag_anchor_pos = selection_start;  // Allow extending from word start
            is_dragging = true;
        } else if (click_count == 3) {
            // Triple-click: select all
            select_all();
            is_dragging = false;
        }

        update_cursor_and_selection_targets();
        reset_cursor_blink();
        return true;
    }

    bool on_mouse_move(float x, float y) override {
        (void)y;

        if (!is_dragging) return false;

        // When captured, x is absolute - convert to widget-relative
        // (EventDispatcher passes absolute coords when widget has capture)
        float widget_x = x - rect.x;
        size_t pos = get_char_index_at(widget_x);

        // Update selection based on drag
        if (click_count == 2) {
            // Word-drag: extend by word boundaries
            size_t word_start = get_word_boundary_left(pos);
            size_t word_end = get_word_boundary_right(pos);

            if (pos < drag_anchor_pos) {
                selection_start = word_start;
                selection_end = get_word_boundary_right(drag_anchor_pos);
            } else {
                selection_start = get_word_boundary_left(drag_anchor_pos);
                selection_end = word_end;
            }
            cursor_pos = (pos < drag_anchor_pos) ? selection_start : selection_end;
        } else {
            // Character-drag: simple selection
            selection_start = drag_anchor_pos;
            selection_end = pos;
            cursor_pos = pos;
        }

        // During drag, snap selection and cursor instantly (no animation delay)
        update_cursor_and_selection_targets_instant();
        return true;
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y; (void)button;

        is_dragging = false;
        return true;
    }

    bool on_double_click(float x, float y, int button) override {
        (void)y;
        if (button != 0) return false;

        // Double-click is also handled by on_mouse_down's multi-click detection
        // This override ensures the event is consumed
        size_t click_pos = get_char_index_at(x);
        select_word_at(click_pos);
        update_cursor_and_selection_targets();
        reset_cursor_blink();
        return true;
    }

private:
    size_t find_word_start(size_t pos) {
        while (pos > 0 && !iswalnum(text[pos - 1])) pos--;
        while (pos > 0 && iswalnum(text[pos - 1])) pos--;
        return pos;
    }

    size_t find_word_end(size_t pos) {
        while (pos < text_len && !iswalnum(text[pos])) pos++;
        while (pos < text_len && iswalnum(text[pos])) pos++;
        return pos;
    }

    // Word boundary helpers for selection
    size_t get_word_boundary_left(size_t pos) {
        if (pos == 0) return 0;
        // Skip any whitespace/punctuation immediately before pos
        while (pos > 0 && !iswalnum(text[pos - 1])) pos--;
        // Find start of word
        while (pos > 0 && iswalnum(text[pos - 1])) pos--;
        return pos;
    }

    size_t get_word_boundary_right(size_t pos) {
        if (pos >= text_len) return text_len;
        // If on alphanumeric, find end of word
        if (iswalnum(text[pos])) {
            while (pos < text_len && iswalnum(text[pos])) pos++;
        } else {
            // Skip whitespace/punctuation
            while (pos < text_len && !iswalnum(text[pos])) pos++;
        }
        return pos;
    }

    void delete_selection() {
        if (selection_start == selection_end) return;

        size_t sel_min = selection_start < selection_end ? selection_start : selection_end;
        size_t sel_max = selection_start > selection_end ? selection_start : selection_end;

        memmove(&text[sel_min], &text[sel_max], (text_len - sel_max + 1) * sizeof(wchar_t));
        text_len -= (sel_max - sel_min);
        cursor_pos = sel_min;
        selection_start = selection_end = cursor_pos;
        content_width_dirty = true;
        update_cursor_and_selection_targets();
        notify_change();
    }

    void copy_to_clipboard() {
        if (selection_start == selection_end) return;

        size_t sel_min = selection_start < selection_end ? selection_start : selection_end;
        size_t sel_max = selection_start > selection_end ? selection_start : selection_end;
        size_t len = sel_max - sel_min;

        if (OpenClipboard(nullptr)) {
            EmptyClipboard();
            HGLOBAL hg = GlobalAlloc(GMEM_MOVEABLE, (len + 1) * sizeof(wchar_t));
            if (hg) {
                wchar_t* dst = (wchar_t*)GlobalLock(hg);
                if (dst) {
                    memcpy(dst, &text[sel_min], len * sizeof(wchar_t));
                    dst[len] = L'\0';
                    GlobalUnlock(hg);
                    SetClipboardData(CF_UNICODETEXT, hg);
                }
            }
            CloseClipboard();
        }
    }

    void paste_from_clipboard() {
        if (!OpenClipboard(nullptr)) return;

        HANDLE hData = GetClipboardData(CF_UNICODETEXT);
        if (hData) {
            wchar_t* src = (wchar_t*)GlobalLock(hData);
            if (src) {
                // Delete selection first
                if (selection_start != selection_end) {
                    delete_selection();
                }

                size_t paste_len = wcslen(src);
                size_t available = 1022 - text_len;
                if (paste_len > available) paste_len = available;

                if (paste_len > 0) {
                    memmove(&text[cursor_pos + paste_len], &text[cursor_pos], (text_len - cursor_pos + 1) * sizeof(wchar_t));
                    memcpy(&text[cursor_pos], src, paste_len * sizeof(wchar_t));
                    cursor_pos += paste_len;
                    text_len += paste_len;
                    selection_start = selection_end = cursor_pos;
                    content_width_dirty = true;
                    update_cursor_and_selection_targets();
                    reset_cursor_blink();
                    notify_change();
                }

                GlobalUnlock(hData);
            }
        }
        CloseClipboard();
    }

    size_t get_char_index_at(float x) {
        if (text_len == 0) return 0;

        IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_body;
        if (!fmt || !g_dwrite_factory) return 0;

        // x is already relative to widget rect (EventDispatcher subtracts rect.x)
        // Convert to text-local coordinates (relative to content area, accounting for scroll)
        float local_x = x - padding_left + scroll_offset;

        const wchar_t* display_text = text;
        wchar_t dots[1024];
        if (password_mode) {
            for (size_t i = 0; i < text_len && i < 1023; i++) dots[i] = L'\x2022';
            dots[text_len] = L'\0';
            display_text = dots;
        }

        IDWriteTextLayout* layout = nullptr;
        g_dwrite_factory->CreateTextLayout(
            display_text, static_cast<UINT32>(text_len), fmt,
            10000.0f,  // Large width to avoid wrapping
            rect.height - padding_top - padding_bottom,
            &layout
        );

        size_t result = 0;
        if (layout) {
            BOOL trailing, inside;
            DWRITE_HIT_TEST_METRICS metrics;
            layout->HitTestPoint(local_x, 0, &trailing, &inside, &metrics);
            result = metrics.textPosition;
            if (trailing) result++;
            if (result > text_len) result = text_len;
            layout->Release();
        }

        return result;
    }

    // Get cursor X position in text coordinates (before scroll offset)
    float get_cursor_x_in_text() {
        if (text_len == 0) return 0.0f;

        IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_body;
        if (!fmt || !g_dwrite_factory) return 0.0f;

        const wchar_t* display_text = text;
        wchar_t dots[1024];
        if (password_mode) {
            for (size_t i = 0; i < text_len && i < 1023; i++) dots[i] = L'\x2022';
            dots[text_len] = L'\0';
            display_text = dots;
        }

        IDWriteTextLayout* layout = nullptr;
        g_dwrite_factory->CreateTextLayout(
            display_text, static_cast<UINT32>(text_len), fmt,
            10000.0f,
            rect.height - padding_top - padding_bottom,
            &layout
        );

        float result = 0.0f;
        if (layout) {
            DWRITE_HIT_TEST_METRICS metrics;
            float x, y;
            layout->HitTestTextPosition(static_cast<UINT32>(cursor_pos), FALSE, &x, &y, &metrics);
            result = x;
            layout->Release();
        }

        return result;
    }

    // Get X position for a text position
    float get_x_for_position(size_t pos) {
        if (text_len == 0 || pos == 0) return 0.0f;

        IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_body;
        if (!fmt || !g_dwrite_factory) return 0.0f;

        const wchar_t* display_text = text;
        wchar_t dots[1024];
        if (password_mode) {
            for (size_t i = 0; i < text_len && i < 1023; i++) dots[i] = L'\x2022';
            dots[text_len] = L'\0';
            display_text = dots;
        }

        IDWriteTextLayout* layout = nullptr;
        g_dwrite_factory->CreateTextLayout(
            display_text, static_cast<UINT32>(text_len), fmt,
            10000.0f,
            rect.height - padding_top - padding_bottom,
            &layout
        );

        float result = 0.0f;
        if (layout) {
            DWRITE_HIT_TEST_METRICS metrics;
            float x, y;
            layout->HitTestTextPosition(static_cast<UINT32>(pos), FALSE, &x, &y, &metrics);
            result = x;
            layout->Release();
        }

        return result;
    }

    // Update animated cursor and selection targets
    void update_cursor_and_selection_targets() {
        // Update cursor target
        cursor_target_x = get_cursor_x_in_text();

        // Initialize current position if not done yet
        if (!cursor_x_initialized) {
            cursor_current_x = cursor_target_x;
            cursor_x_initialized = true;
        }

        // Update selection targets
        sel_target_start_x = get_x_for_position(selection_start);
        sel_target_end_x = get_x_for_position(selection_end);

        // If no selection, snap animation
        if (selection_start == selection_end) {
            sel_anim_start_x = sel_target_start_x;
            sel_anim_end_x = sel_target_end_x;
        }

        // Ensure cursor is visible (scroll if needed)
        ensure_cursor_visible();

        // Trigger repaint to start animation
        set_dirty();
    }

    // Update cursor and selection instantly (no animation) - used during drag
    void update_cursor_and_selection_targets_instant() {
        // Update and snap cursor position
        cursor_target_x = get_cursor_x_in_text();
        cursor_current_x = cursor_target_x;
        cursor_x_initialized = true;

        // Update and snap selection bounds
        sel_target_start_x = get_x_for_position(selection_start);
        sel_target_end_x = get_x_for_position(selection_end);
        sel_anim_start_x = sel_target_start_x;
        sel_anim_end_x = sel_target_end_x;

        // Ensure cursor is visible (scroll if needed)
        ensure_cursor_visible();

        // Trigger repaint
        set_dirty();
    }

    // Ensure cursor is visible within the scroll viewport
    void ensure_cursor_visible() {
        float visible_width = rect.width - padding_left - padding_right;
        float margin = TextInputTheme::SCROLL_MARGIN;

        // Calculate where cursor would appear on screen
        float cursor_screen_x = cursor_target_x - scroll_offset;

        if (cursor_screen_x < margin) {
            // Cursor is off the left edge - scroll left
            scroll_offset = fmaxf(0.0f, cursor_target_x - margin);
        } else if (cursor_screen_x > visible_width - margin) {
            // Cursor is off the right edge - scroll right
            scroll_offset = cursor_target_x - visible_width + margin;
        }
    }

    // Reset cursor blink timer (call on any cursor activity)
    void reset_cursor_blink() {
        cursor_blink_timer = 0.0f;
        cursor_opacity = 1.0f;
        cursor_blink_pause_timer = 0.5f;  // Pause blinking for 500ms after cursor activity
    }

    // Select word at position
    void select_word_at(size_t pos) {
        if (text_len == 0) return;

        // Clamp pos to valid range
        if (pos >= text_len) pos = text_len > 0 ? text_len - 1 : 0;

        if (iswalnum(text[pos])) {
            // On a word character - select the word
            selection_start = pos;
            while (selection_start > 0 && iswalnum(text[selection_start - 1])) {
                selection_start--;
            }
            selection_end = pos;
            while (selection_end < text_len && iswalnum(text[selection_end])) {
                selection_end++;
            }
        } else {
            // On whitespace/punctuation - select the sequence
            selection_start = pos;
            while (selection_start > 0 && !iswalnum(text[selection_start - 1])) {
                selection_start--;
            }
            selection_end = pos;
            while (selection_end < text_len && !iswalnum(text[selection_end])) {
                selection_end++;
            }
        }

        cursor_pos = selection_end;
    }

    // Select all text
    void select_all() {
        selection_start = 0;
        selection_end = text_len;
        cursor_pos = text_len;
        update_cursor_and_selection_targets();
        reset_cursor_blink();
    }

    // === Undo/Redo Methods ===

    void push_undo_state() {
        if (!undo_stack) {
            undo_stack = new TextInputUndoStack();
        }
        undo_stack->push(text, text_len, cursor_pos, selection_start, selection_end);
    }

    void enable_undo_coalescing() {
        if (undo_stack) {
            undo_stack->enable_coalescing();
        }
    }

    void undo() {
        if (!undo_stack || !undo_stack->can_undo()) return;

        undo_stack->undo(text, &text_len, &cursor_pos, &selection_start, &selection_end);
        content_width_dirty = true;
        update_cursor_and_selection_targets();
        reset_cursor_blink();
        notify_change();
    }

    void redo() {
        if (!undo_stack || !undo_stack->can_redo()) return;

        undo_stack->redo(text, &text_len, &cursor_pos, &selection_start, &selection_end);
        content_width_dirty = true;
        update_cursor_and_selection_targets();
        reset_cursor_blink();
        notify_change();
    }

public:
    // Public API for error state
    void trigger_error_shake() {
        error_shake_timer = TextInputTheme::SHAKE_DURATION_MS / 1000.0f;
        has_error = true;
    }

    void set_error(bool error) {
        has_error = error;
        if (!error) {
            error_shake_offset = 0.0f;
            error_shake_timer = 0.0f;
        }
    }

    void clear_error() {
        set_error(false);
    }

private:
    void notify_change() {
        if (on_change) {
            on_change(this, user_data);
        }
    }

public:
    // TSF accessor: set text range (used by TSF SetText)
    // Must be public for textinput_set_text_range() accessor function
    void tsf_set_text_impl(size_t start, size_t end, const wchar_t* new_text, size_t new_len) {
        if (start > text_len) start = text_len;
        if (end > text_len) end = text_len;
        if (start > end) start = end;

        size_t old_len = end - start;
        size_t available = 1022 - (text_len - old_len);
        if (new_len > available) new_len = available;

        // Make room for new text
        memmove(&text[start + new_len], &text[end], (text_len - end + 1) * sizeof(wchar_t));

        // Copy new text
        if (new_text && new_len > 0) {
            memcpy(&text[start], new_text, new_len * sizeof(wchar_t));
        }

        // Update length
        text_len = text_len - old_len + new_len;
        text[text_len] = L'\0';

        // Update cursor to end of inserted text
        cursor_pos = start + new_len;
        selection_start = selection_end = cursor_pos;

        // Trigger change callback
        notify_change();
        set_dirty();
    }
};

// ============================================================================
// TSF Accessor Functions for TextInput
// ============================================================================
// These functions provide TsfTextStore access to TextInput internals.
// They're defined here because TextInput must be fully defined first.
// Not static - needed by tsf_text_store.cpp which is included after this file.

const wchar_t* textinput_get_text(TextInput* input) {
    return input ? input->text : L"";
}

size_t textinput_get_text_len(TextInput* input) {
    return input ? input->text_len : 0;
}

void textinput_get_selection(TextInput* input, size_t* start, size_t* end) {
    if (!input || !start || !end) return;
    *start = input->selection_start;
    *end = input->selection_end;
}

void textinput_set_selection(TextInput* input, size_t start, size_t end) {
    if (!input) return;
    if (start > input->text_len) start = input->text_len;
    if (end > input->text_len) end = input->text_len;
    input->selection_start = start;
    input->selection_end = end;
    input->cursor_pos = end;
    input->set_dirty();
}

void textinput_set_text_range(TextInput* input, size_t start, size_t end,
                              const wchar_t* text, size_t len) {
    if (!input) return;
    input->tsf_set_text_impl(start, end, text, len);
}

void textinput_get_rect(TextInput* input, float* x, float* y, float* width, float* height) {
    if (!input || !x || !y || !width || !height) return;
    *x = input->rect.x;
    *y = input->rect.y;
    *width = input->rect.width;
    *height = input->rect.height;
}

// Forward declaration - g_main_window is defined in platform.cpp
extern HWND g_main_window;

HWND textinput_get_hwnd() {
    return g_main_window;
}

// ============================================================================
// Checkbox Widget
// ============================================================================

struct Checkbox : Widget {
    bool checked = false;
    const wchar_t* label = L"";
    IDWriteTextFormat* text_format = nullptr;  // nullptr = use default

    // Appearance (using BranchDialog constants for consistency)
    float box_size = BranchDialog::CHECKBOX_SIZE;  // 16.0f
    float box_radius = BranchDialog::CHECKBOX_RADIUS;  // 3.0f
    float label_spacing = BranchDialog::CHECKBOX_LABEL_SPACING;  // 8.0f

    uint32_t box_bg = 0xFF1E1E1E;
    uint32_t box_border = 0xFF3C3C3C;
    uint32_t box_border_hover = Theme::ACCENT;
    uint32_t check_color = BranchDialog::CHECKBOX_CHECK;  // Theme::ACCENT
    uint32_t label_color = Theme::TEXT_PRIMARY;

    // Callback
    void (*on_change)(Checkbox* cb, bool checked, void* user_data) = nullptr;
    void* user_data = nullptr;

    Checkbox() {
        flags |= WidgetFlags::Focusable;
        preferred_height = 20.0f;  // Checkbox + some padding
    }

    void measure(const LayoutConstraints& constraints) override {
        IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_body;

        // Box + spacing + label width
        float label_width = 0.0f;

        if (label && label[0] && fmt && g_dwrite_factory) {
            IDWriteTextLayout* layout = nullptr;
            size_t len = wcslen(label);
            HRESULT hr = g_dwrite_factory->CreateTextLayout(
                label, static_cast<UINT32>(len), fmt,
                1000.0f, 1000.0f, &layout
            );

            if (SUCCEEDED(hr) && layout) {
                DWRITE_TEXT_METRICS metrics;
                layout->GetMetrics(&metrics);
                label_width = metrics.width;
                layout->Release();
            }
        }

        preferred_width = box_size + label_spacing + label_width + padding_left + padding_right;
        preferred_height = fmaxf(box_size, 20.0f) + padding_top + padding_bottom;

        Widget::measure(constraints);
    }

    void render(RenderContext& ctx) override {
        float box_x = rect.x + padding_left;
        float box_y = rect.y + (rect.height - box_size) / 2.0f;

        D2D1_RECT_F box_rect = D2D1::RectF(box_x, box_y, box_x + box_size, box_y + box_size);

        // Draw box background
        ctx.fill_rounded_rect(box_rect, box_radius, box_bg);

        // Draw box border - show hover state
        uint32_t border = box_border;
        if (flags & WidgetFlags::Hovered) {
            border = box_border_hover;
        }
        ctx.brush->SetColor(color_from_argb(border));
        D2D1_ROUNDED_RECT rr = { box_rect, box_radius, box_radius };
        ctx.target->DrawRoundedRectangle(rr, ctx.brush, 1.0f);

        // Draw focus ring with glow when keyboard focused
        if (flags & WidgetFlags::KeyboardFocused) {
            ctx.draw_focus_ring(box_rect, box_radius);
        }

        // Draw checkmark if checked
        if (checked) {
            ctx.brush->SetColor(color_from_argb(check_color));

            // Draw a simple checkmark using lines
            float cx = box_x + box_size / 2.0f;
            float cy = box_y + box_size / 2.0f;
            float scale = box_size / 16.0f;  // Scale based on 16px reference

            // Checkmark path: start at left-middle, go to bottom-center, then to top-right
            D2D1_POINT_2F p1 = D2D1::Point2F(cx - 4.0f * scale, cy);
            D2D1_POINT_2F p2 = D2D1::Point2F(cx - 1.0f * scale, cy + 3.0f * scale);
            D2D1_POINT_2F p3 = D2D1::Point2F(cx + 4.0f * scale, cy - 3.0f * scale);

            ctx.target->DrawLine(p1, p2, ctx.brush, 2.0f);
            ctx.target->DrawLine(p2, p3, ctx.brush, 2.0f);
        }

        // Draw label
        if (label && label[0]) {
            IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_body;
            if (fmt) {
                float label_x = box_x + box_size + label_spacing;
                D2D1_RECT_F label_rect = D2D1::RectF(
                    label_x,
                    rect.y,
                    rect.x + rect.width - padding_right,
                    rect.y + rect.height
                );
                ctx.draw_text(label, wcslen(label), fmt, label_rect, label_color);
            }
        }
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;

        // Toggle with Space key when focused
        if (vk == VK_SPACE) {
            checked = !checked;
            if (on_change) {
                on_change(this, checked, user_data);
            }
            return true;
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x; (void)y; (void)button;

        // Toggle checked state
        checked = !checked;

        // Fire callback
        if (on_change) {
            on_change(this, checked, user_data);
        }

        return true;
    }
};

// ============================================================================
// SectionHeader Widget
// ============================================================================
// A collapsible section header for sidebar sections (STAGED, CHANGES, BRANCHES)
// Features: chevron (collapse indicator), title, count badge, optional action button

struct SectionHeader : Widget {
    // Section identity
    const wchar_t* title = L"SECTION";
    size_t item_count = 0;

    // Collapse state
    bool collapsed = false;
    bool collapsible = true;  // Some sections (like BRANCHES) may not be collapsible

    // Action button (optional - e.g., "+" for create branch, "-" for unstage all)
    const wchar_t* action_text = nullptr;  // First char is shown as button text
    bool show_action_on_hover_only = true;  // Action button only visible when hovered

    // Appearance (using existing Sidebar theme constants)
    float height = Sidebar::SECTION_HEADER_HEIGHT;  // 28.0f
    float chevron_size = 4.0f;
    float badge_width = 24.0f;
    float badge_height = 16.0f;
    float action_button_size = 18.0f;

    // Colors
    uint32_t bg_color = 0x00000000;           // Transparent by default
    uint32_t bg_hover = Theme::BG_HOVER;
    uint32_t title_color = Theme::TEXT_SECONDARY;
    uint32_t chevron_color = Theme::TEXT_MUTED;
    uint32_t badge_bg = Theme::BG_TERTIARY;
    uint32_t badge_text_color = Theme::TEXT_SECONDARY;
    uint32_t action_bg = Theme::BG_TERTIARY;
    uint32_t action_bg_hover = Theme::ACCENT;
    uint32_t action_text_color = Theme::TEXT_SECONDARY;
    uint32_t action_text_hover = 0xFFFFFFFF;

    // Hover state for subcomponents
    bool header_hovered = false;
    bool action_hovered = false;

    // Callbacks
    void (*on_toggle)(SectionHeader* header, bool collapsed, void* user_data) = nullptr;
    void (*on_action)(SectionHeader* header, void* user_data) = nullptr;
    void* user_data = nullptr;

    SectionHeader() {
        preferred_height = height;
        height_mode = SizeMode::Fixed;
    }

    void measure(const LayoutConstraints& constraints) override {
        preferred_height = height;
        preferred_width = constraints.max_width;
        rect.width = preferred_width;
        rect.height = preferred_height;
    }

    void render(RenderContext& ctx) override {
        // Layout constants
        constexpr float chevron_offset = 2.0f;       // Offset for down-chevron points
        constexpr float chevron_span = 6.0f;         // Width span for down-chevron
        constexpr float title_left_offset = 14.0f;   // Space after chevron for title
        constexpr float right_reserve = 80.0f;       // Space reserved on right for badges/actions
        constexpr float action_corner_radius = 3.0f; // Action button corner radius

        D2D1_RECT_F bg_rect = D2D1::RectF(
            rect.x, rect.y,
            rect.x + rect.width, rect.y + rect.height
        );

        // Background - show hover state (but not over action button area)
        if (header_hovered && !action_hovered) {
            ctx.fill_rect(bg_rect, bg_hover);
        }

        // === Chevron (collapse indicator) ===
        if (collapsible) {
            float chevron_x = rect.x + Theme::PADDING;
            float chevron_y = rect.y + rect.height / 2.0f;

            ctx.brush->SetColor(color_from_argb(chevron_color));

            if (collapsed) {
                // Right-pointing chevron (>)
                ctx.target->DrawLine(
                    D2D1::Point2F(chevron_x, chevron_y - chevron_size),
                    D2D1::Point2F(chevron_x + chevron_size, chevron_y),
                    ctx.brush, 1.0f);
                ctx.target->DrawLine(
                    D2D1::Point2F(chevron_x + chevron_size, chevron_y),
                    D2D1::Point2F(chevron_x, chevron_y + chevron_size),
                    ctx.brush, 1.0f);
            } else {
                // Down-pointing chevron (v)
                ctx.target->DrawLine(
                    D2D1::Point2F(chevron_x - chevron_offset, chevron_y - chevron_offset),
                    D2D1::Point2F(chevron_x + chevron_offset, chevron_y + chevron_offset),
                    ctx.brush, 1.0f);
                ctx.target->DrawLine(
                    D2D1::Point2F(chevron_x + chevron_offset, chevron_y + chevron_offset),
                    D2D1::Point2F(chevron_x + chevron_span, chevron_y - chevron_offset),
                    ctx.brush, 1.0f);
            }
        }

        // === Title ===
        float title_left = rect.x + Theme::PADDING + title_left_offset;
        float title_right = rect.x + rect.width - right_reserve;
        D2D1_RECT_F title_rect = D2D1::RectF(title_left, rect.y, title_right, rect.y + rect.height);

        // DEBUG: Log render details for COMMIT headers
        if (title && wcsncmp(title, L"COMMIT", 6) == 0) {
            LOG("[SectionHeader] Rendering COMMIT header: title='%S', rect=(%.1f,%.1f,%.1f,%.1f), Visible=%d",
                title, rect.x, rect.y, rect.width, rect.height, (flags & WidgetFlags::Visible) != 0);
        }

        if (g_text_format_header && title && title[0]) {
            ctx.draw_text(title, wcslen(title), g_text_format_header, title_rect, title_color);
        } else {
            // DEBUG: Log why title isn't rendering
            if (!g_text_format_header) {
                LOG("[SectionHeader] Title not rendered: g_text_format_header is NULL");
            } else if (!title) {
                LOG("[SectionHeader] Title not rendered: title is NULL");
            } else if (!title[0]) {
                LOG("[SectionHeader] Title not rendered: title[0] is 0 (empty string)");
            }
        }

        // === Count Badge (pill shape, right side) ===
        if (item_count > 0) {
            wchar_t count_str[16];
            swprintf_s(count_str, L"%zu", item_count);

            float badge_x = rect.x + rect.width - badge_width - Theme::PADDING;
            float badge_y = rect.y + (rect.height - badge_height) / 2.0f;

            D2D1_ROUNDED_RECT badge_rounded = D2D1::RoundedRect(
                D2D1::RectF(badge_x, badge_y, badge_x + badge_width, badge_y + badge_height),
                badge_height / 2.0f, badge_height / 2.0f
            );

            ctx.brush->SetColor(color_from_argb(badge_bg));
            ctx.target->FillRoundedRectangle(badge_rounded, ctx.brush);

            D2D1_RECT_F count_rect = D2D1::RectF(badge_x, badge_y, badge_x + badge_width, badge_y + badge_height);
            if (g_text_format_badge) {
                ctx.draw_text(count_str, wcslen(count_str), g_text_format_badge, count_rect, badge_text_color);
            }
        }

        // === Action Button (left of count badge) ===
        // Only show if: action_text is set, and either always visible or header is hovered
        bool show_action = action_text != nullptr &&
                          ((!show_action_on_hover_only) || header_hovered);

        if (show_action && item_count > 0) {
            float action_x = rect.x + rect.width - badge_width - Theme::PADDING -
                             action_button_size - Theme::PADDING;
            float action_y = rect.y + (rect.height - action_button_size) / 2.0f;

            D2D1_ROUNDED_RECT action_rounded = D2D1::RoundedRect(
                D2D1::RectF(action_x, action_y, action_x + action_button_size, action_y + action_button_size),
                action_corner_radius, action_corner_radius
            );

            // Background color based on hover state
            uint32_t btn_bg = action_hovered ? action_bg_hover : action_bg;
            uint32_t btn_text = action_hovered ? action_text_hover : action_text_color;

            ctx.brush->SetColor(color_from_argb(btn_bg));
            ctx.target->FillRoundedRectangle(action_rounded, ctx.brush);

            // Draw first character of action_text as the button symbol
            wchar_t symbol[2] = { action_text[0], L'\0' };
            D2D1_RECT_F action_text_rect = D2D1::RectF(
                action_x, action_y,
                action_x + action_button_size, action_y + action_button_size
            );
            if (g_text_format_badge) {
                ctx.draw_text(symbol, 1, g_text_format_badge, action_text_rect, btn_text);
            }
        }
    }

    bool on_mouse_move(float x, float y) override {
        (void)y;

        bool was_header_hovered = header_hovered;
        bool was_action_hovered = action_hovered;

        // Check if over action button
        action_hovered = false;
        if (action_text && item_count > 0) {
            float action_x = rect.x + rect.width - badge_width - Theme::PADDING - action_button_size - Theme::PADDING;
            float action_right = action_x + action_button_size;

            // Use absolute coordinates (x is relative to widget)
            float abs_x = rect.x + x;
            if (abs_x >= action_x && abs_x < action_right) {
                action_hovered = true;
            }
        }

        // Header is hovered if mouse is in widget bounds
        header_hovered = true;

        if (was_header_hovered != header_hovered || was_action_hovered != action_hovered) {
            set_dirty();
        }

        return false;  // Don't consume - let parent handle other logic
    }

    bool on_mouse_enter() override {
        header_hovered = true;
        set_dirty();
        return false;
    }

    bool on_mouse_leave() override {
        header_hovered = false;
        action_hovered = false;
        set_dirty();
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x; (void)y; (void)button;

        // Check if click is on action button
        if (action_text && action_hovered) {
            if (on_action) {
                on_action(this, user_data);
            }
            return true;
        }

        // Otherwise, toggle collapse state (if collapsible)
        if (collapsible) {
            collapsed = !collapsed;
            if (on_toggle) {
                on_toggle(this, collapsed, user_data);
            }
            set_dirty();
            return true;
        }

        return false;
    }

    // Helper to calculate action button hit rect (for external hit testing)
    bool hit_test_action(float x, float y) const {
        if (!action_text || item_count == 0) return false;

        float action_x = rect.x + rect.width - badge_width - Theme::PADDING - action_button_size - Theme::PADDING;
        float action_y = rect.y + (rect.height - action_button_size) / 2.0f;

        return (x >= action_x && x < action_x + action_button_size &&
                y >= action_y && y < action_y + action_button_size);
    }

    // Helper to update count without full rebuild
    void set_count(size_t count) {
        if (item_count != count) {
            item_count = count;
            set_dirty();
        }
    }

    // Helper to set collapsed state programmatically
    void set_collapsed(bool state) {
        if (collapsed != state) {
            collapsed = state;
            set_dirty();
        }
    }

    // Helper to set title label
    void set_label(const wchar_t* label) {
        if (title != label) {
            title = label;
            set_dirty();
        }
    }

    // Helper to set action button label
    void set_action_label(const wchar_t* label) {
        if (action_text != label) {
            action_text = label;
            set_dirty();
        }
    }
};

// ============================================================================
// CommitViewHeader - Accent-colored header for commit view mode
// ============================================================================
// Layout:
// ┌─────────────────────────────────────────┐
// │ COMMIT: abc1234                  (5) [×]│  ← Accent background
// │ John Doe • 3 days ago                   │  ← Author + relative time
// │ ┌─────────────────────────────────────┐ │
// │ │ Commit message line 1              │ │  ← Scrollable message (max 7 lines)
// │ │ Line 2...                          │ │
// │ └─────────────────────────────────────┘ │
// └─────────────────────────────────────────┘

struct CommitViewHeader : Widget {
    // Commit data (set externally)
    wchar_t short_sha[16] = {};           // "abc1234"
    wchar_t author[64] = {};              // "John Doe"
    wchar_t relative_time[32] = {};       // "3 days ago"
    wchar_t message[2048] = {};           // Full commit message
    size_t file_count = 0;                // Number of files changed

    // Callbacks
    void (*on_close)(CommitViewHeader* header, void* user_data) = nullptr;
    void* user_data = nullptr;

    // Layout constants
    static constexpr float TITLE_LINE_HEIGHT = 24.0f;
    static constexpr float AUTHOR_LINE_HEIGHT = 18.0f;
    static constexpr float MESSAGE_LINE_HEIGHT = 16.0f;
    static constexpr float MAX_MESSAGE_LINES = 7.0f;
    static constexpr float CLOSE_BUTTON_SIZE = 20.0f;
    static constexpr float BADGE_WIDTH = 28.0f;
    static constexpr float BADGE_HEIGHT = 18.0f;
    static constexpr float BADGE_CLOSE_SPACING = 12.0f;  // Space between badge and close button

    // Scroll state for message
    float message_scroll_y = 0.0f;
    float message_content_height = 0.0f;  // Actual wrapped content height
    float message_visible_height = 0.0f;  // Clamped to MAX_MESSAGE_LINES
    int message_line_count = 0;  // Approximate lines for scrollbar

    // Cached text layout for wrapped message
    IDWriteTextLayout* message_layout = nullptr;
    float last_layout_width = 0.0f;  // Width used for last layout

    // Hover state
    bool close_hovered = false;

    // Scrollbar drag state
    bool scrollbar_dragging = false;
    float scrollbar_drag_start_y = 0.0f;
    float scrollbar_drag_start_scroll = 0.0f;

    CommitViewHeader() {
        flags |= WidgetFlags::Focusable;
    }

    ~CommitViewHeader() {
        if (message_layout) {
            message_layout->Release();
            message_layout = nullptr;
        }
    }

    void set_commit(const char* sha, const char* author_name, int64_t timestamp,
                    const char* msg, size_t num_files) {
        // Convert SHA (ASCII-only by construction)
        for (int i = 0; i < 7 && sha && sha[i]; i++) {
            short_sha[i] = static_cast<wchar_t>(sha[i]);
        }
        short_sha[7] = L'\0';

        // Convert author from UTF-8 to UTF-16 properly so non-ASCII (CJK, accents,
        // emoji) doesn't render as garbled bytes. -1 length lets the API also
        // null-terminate the destination.
        author[0] = L'\0';
        if (author_name && author_name[0]) {
            int r = MultiByteToWideChar(CP_UTF8, 0, author_name, -1,
                                        author, static_cast<int>(_countof(author)));
            if (r <= 0) {
                // Fallback: zero-out so we don't render uninitialized data.
                author[0] = L'\0';
            } else {
                author[_countof(author) - 1] = L'\0';
            }
        }

        // Format relative time
        format_relative_time(timestamp, relative_time, 32);

        // Convert message UTF-8 -> UTF-16.
        message[0] = L'\0';
        if (msg && msg[0]) {
            int r = MultiByteToWideChar(CP_UTF8, 0, msg, -1,
                                        message, static_cast<int>(_countof(message)));
            if (r <= 0) {
                message[0] = L'\0';
            } else {
                message[_countof(message) - 1] = L'\0';
            }
        }

        // Invalidate cached layout when message changes
        if (message_layout) {
            message_layout->Release();
            message_layout = nullptr;
        }
        last_layout_width = 0.0f;
        message_content_height = 0.0f;
        message_visible_height = 0.0f;
        message_line_count = 0;

        file_count = num_files;
        message_scroll_y = 0.0f;
        set_dirty();
    }

    static void format_relative_time(int64_t timestamp, wchar_t* out, size_t out_size) {
        int64_t now = static_cast<int64_t>(time(nullptr));
        int64_t diff = now - timestamp;

        if (diff < 60) {
            swprintf_s(out, out_size, L"just now");
        } else if (diff < 3600) {
            int mins = static_cast<int>(diff / 60);
            swprintf_s(out, out_size, L"%d min%ls ago", mins, mins == 1 ? L"" : L"s");
        } else if (diff < 86400) {
            int hours = static_cast<int>(diff / 3600);
            swprintf_s(out, out_size, L"%d hour%ls ago", hours, hours == 1 ? L"" : L"s");
        } else if (diff < 604800) {
            int days = static_cast<int>(diff / 86400);
            swprintf_s(out, out_size, L"%d day%ls ago", days, days == 1 ? L"" : L"s");
        } else if (diff < 2592000) {
            int weeks = static_cast<int>(diff / 604800);
            swprintf_s(out, out_size, L"%d week%ls ago", weeks, weeks == 1 ? L"" : L"s");
        } else {
            int months = static_cast<int>(diff / 2592000);
            swprintf_s(out, out_size, L"%d month%ls ago", months, months == 1 ? L"" : L"s");
        }
    }

    // Create/update text layout for wrapped message
    void update_message_layout(float available_width) {
        // Skip if width hasn't changed and we already have a layout
        if (message_layout && fabsf(last_layout_width - available_width) < 1.0f) {
            return;
        }

        // Release old layout
        if (message_layout) {
            message_layout->Release();
            message_layout = nullptr;
        }

        if (!g_dwrite_factory || !g_text_format_path || !message[0]) {
            message_content_height = MESSAGE_LINE_HEIGHT;
            message_visible_height = MESSAGE_LINE_HEIGHT;
            message_line_count = 1;
            return;
        }

        last_layout_width = available_width;

        // Create a text format WITHOUT vertical centering (g_text_format_path has CENTER)
        // DWRITE_PARAGRAPH_ALIGNMENT defaults to NEAR (top) if not set
        IDWriteTextFormat* msg_format = nullptr;
        HRESULT hr = g_dwrite_factory->CreateTextFormat(
            L"Segoe UI", nullptr,
            DWRITE_FONT_WEIGHT_NORMAL, DWRITE_FONT_STYLE_NORMAL, DWRITE_FONT_STRETCH_NORMAL,
            10.0f, L"en-US", &msg_format);

        if (!SUCCEEDED(hr) || !msg_format) {
            message_content_height = MESSAGE_LINE_HEIGHT;
            message_visible_height = MESSAGE_LINE_HEIGHT;
            message_line_count = 1;
            return;
        }

        msg_format->SetWordWrapping(DWRITE_WORD_WRAPPING_WRAP);

        // Create layout with the non-centered format
        hr = g_dwrite_factory->CreateTextLayout(
            message, static_cast<UINT32>(wcslen(message)),
            msg_format,
            available_width,
            10000.0f,  // Large height for measurement
            &message_layout
        );

        msg_format->Release();  // Layout keeps internal reference

        if (SUCCEEDED(hr) && message_layout) {

            // Get metrics to determine actual wrapped height
            DWRITE_TEXT_METRICS metrics;
            message_layout->GetMetrics(&metrics);

            message_content_height = metrics.height;
            float max_visible = MAX_MESSAGE_LINES * MESSAGE_LINE_HEIGHT;
            message_visible_height = fminf(message_content_height, max_visible);
            message_line_count = static_cast<int>(ceilf(message_content_height / MESSAGE_LINE_HEIGHT));
        } else {
            message_content_height = MESSAGE_LINE_HEIGHT;
            message_visible_height = MESSAGE_LINE_HEIGHT;
            message_line_count = 1;
        }
    }

    float calculate_height() const {
        return Theme::PADDING + TITLE_LINE_HEIGHT + AUTHOR_LINE_HEIGHT +
               Theme::PADDING_SMALL + message_visible_height + Theme::PADDING;
    }

    void measure(const LayoutConstraints& constraints) override {
        preferred_width = constraints.max_width;

        // Calculate available width for message (with padding on both sides)
        float msg_width = preferred_width - Theme::PADDING * 2 - Theme::PADDING_SMALL * 2;

        // Update layout with current width - cast away const for mutable layout update
        const_cast<CommitViewHeader*>(this)->update_message_layout(msg_width);

        preferred_height = calculate_height();
        rect.width = preferred_width;
        rect.height = preferred_height;
    }

    void render(RenderContext& ctx) override {
        // Background - full accent color with sharp bottom corners (to merge with border below)
        // Draw as a rectangle with only top corners rounded using a path geometry
        D2D1_RECT_F bg_rect = D2D1::RectF(rect.x, rect.y, rect.x + rect.width, rect.y + rect.height);
        ctx.brush->SetColor(color_from_argb(Theme::ACCENT));

        // Create a rounded rect path with only top corners rounded
        ID2D1PathGeometry* path = nullptr;
        ID2D1Factory* factory = nullptr;
        ctx.target->GetFactory(&factory);
        if (factory && SUCCEEDED(factory->CreatePathGeometry(&path))) {
            ID2D1GeometrySink* sink = nullptr;
            if (SUCCEEDED(path->Open(&sink))) {
                float r = Theme::CORNER_RADIUS;
                float x0 = rect.x, y0 = rect.y;
                float x1 = rect.x + rect.width, y1 = rect.y + rect.height;

                sink->BeginFigure(D2D1::Point2F(x0, y1), D2D1_FIGURE_BEGIN_FILLED);
                sink->AddLine(D2D1::Point2F(x0, y0 + r));
                sink->AddArc(D2D1::ArcSegment(
                    D2D1::Point2F(x0 + r, y0), D2D1::SizeF(r, r),
                    0.0f, D2D1_SWEEP_DIRECTION_CLOCKWISE, D2D1_ARC_SIZE_SMALL));
                sink->AddLine(D2D1::Point2F(x1 - r, y0));
                sink->AddArc(D2D1::ArcSegment(
                    D2D1::Point2F(x1, y0 + r), D2D1::SizeF(r, r),
                    0.0f, D2D1_SWEEP_DIRECTION_CLOCKWISE, D2D1_ARC_SIZE_SMALL));
                sink->AddLine(D2D1::Point2F(x1, y1));
                sink->AddLine(D2D1::Point2F(x0, y1));
                sink->EndFigure(D2D1_FIGURE_END_CLOSED);
                sink->Close();
                sink->Release();

                ctx.target->FillGeometry(path, ctx.brush);
            }
            path->Release();
        }

        float y = rect.y + Theme::PADDING;
        float text_left = rect.x + Theme::PADDING;
        float text_right = rect.x + rect.width - Theme::PADDING;

        // === Title line: "COMMIT: abc1234" + badge + close button ===
        {
            // Close button (right side)
            float close_x = text_right - CLOSE_BUTTON_SIZE;
            float close_y = y + (TITLE_LINE_HEIGHT - CLOSE_BUTTON_SIZE) / 2.0f;

            D2D1_ROUNDED_RECT close_rect = D2D1::RoundedRect(
                D2D1::RectF(close_x, close_y, close_x + CLOSE_BUTTON_SIZE, close_y + CLOSE_BUTTON_SIZE),
                3.0f, 3.0f
            );

            // Close button background on hover
            if (close_hovered) {
                ctx.brush->SetColor(color_from_argb(0x40000000));  // Semi-transparent dark
                ctx.target->FillRoundedRectangle(close_rect, ctx.brush);
            }

            // Close button X using path (centered)
            ctx.brush->SetColor(color_from_argb(0xFFFFFFFF));
            float cx = close_x + CLOSE_BUTTON_SIZE / 2.0f;
            float cy = close_y + CLOSE_BUTTON_SIZE / 2.0f;
            float half_size = 4.0f;  // Half of X size
            ctx.target->DrawLine(
                D2D1::Point2F(cx - half_size, cy - half_size),
                D2D1::Point2F(cx + half_size, cy + half_size),
                ctx.brush, 1.5f);
            ctx.target->DrawLine(
                D2D1::Point2F(cx + half_size, cy - half_size),
                D2D1::Point2F(cx - half_size, cy + half_size),
                ctx.brush, 1.5f);

            // Count badge (left of close button, with extra spacing)
            float badge_x = close_x - BADGE_CLOSE_SPACING - BADGE_WIDTH;
            float badge_y = y + (TITLE_LINE_HEIGHT - BADGE_HEIGHT) / 2.0f;

            D2D1_ROUNDED_RECT badge_rounded = D2D1::RoundedRect(
                D2D1::RectF(badge_x, badge_y, badge_x + BADGE_WIDTH, badge_y + BADGE_HEIGHT),
                BADGE_HEIGHT / 2.0f, BADGE_HEIGHT / 2.0f
            );
            ctx.brush->SetColor(color_from_argb(0x40000000));  // Semi-transparent dark
            ctx.target->FillRoundedRectangle(badge_rounded, ctx.brush);

            wchar_t count_str[16];
            swprintf_s(count_str, L"%zu", file_count);
            D2D1_RECT_F badge_text_rect = D2D1::RectF(badge_x, badge_y, badge_x + BADGE_WIDTH, badge_y + BADGE_HEIGHT);
            if (g_text_format_badge) {
                ctx.draw_text(count_str, wcslen(count_str), g_text_format_badge, badge_text_rect, 0xFFFFFFFF);
            }

            // "COMMIT: abc1234" title
            wchar_t title[32];
            swprintf_s(title, L"COMMIT: %s", short_sha);
            float title_right = badge_x - Theme::PADDING_SMALL;
            D2D1_RECT_F title_rect = D2D1::RectF(text_left, y, title_right, y + TITLE_LINE_HEIGHT);
            if (g_text_format_header) {
                ctx.draw_text(title, wcslen(title), g_text_format_header, title_rect, 0xFFFFFFFF);
            }
        }

        y += TITLE_LINE_HEIGHT;

        // === Author line: "John Doe • 3 days ago" ===
        {
            wchar_t author_line[128];
            swprintf_s(author_line, L"%s \x2022 %s", author, relative_time);  // • bullet
            D2D1_RECT_F author_rect = D2D1::RectF(text_left, y, text_right, y + AUTHOR_LINE_HEIGHT);
            if (g_text_format_path) {
                ctx.draw_text(author_line, wcslen(author_line), g_text_format_path, author_rect, 0xDDFFFFFF);
            }
        }

        y += AUTHOR_LINE_HEIGHT + Theme::PADDING_SMALL;

        // === Message area (scrollable if content > visible height) ===
        // Layout is created in update_message_layout() during measure()

        // Fallback visible height if layout couldn't be created
        float visible_height = message_visible_height > 0.0f ? message_visible_height : MESSAGE_LINE_HEIGHT;
        D2D1_RECT_F msg_clip = D2D1::RectF(text_left, y, text_right, y + visible_height);

        // Message background (slightly darker for contrast)
        D2D1_ROUNDED_RECT msg_bg = D2D1::RoundedRect(msg_clip, 3.0f, 3.0f);
        ctx.brush->SetColor(color_from_argb(0x20000000));
        ctx.target->FillRoundedRectangle(msg_bg, ctx.brush);

        // Clip message area for scrolling
        ctx.push_clip(msg_clip);

        if (message[0] && message_layout) {
            // Draw wrapped message using DrawTextLayout
            // IMPORTANT: Set brush color before DrawTextLayout (not after)
            ctx.brush->SetColor(color_from_argb(0xFFFFFFFF));
            ctx.target->DrawTextLayout(
                D2D1::Point2F(text_left + Theme::PADDING_SMALL, y - message_scroll_y),
                message_layout,
                ctx.brush
            );
        } else if (message[0]) {
            // Fallback: layout creation failed, render first line without wrapping
            D2D1_RECT_F fallback_rect = D2D1::RectF(
                text_left + Theme::PADDING_SMALL, y,
                text_right - Theme::PADDING_SMALL, y + MESSAGE_LINE_HEIGHT
            );
            ctx.draw_text(message, wcslen(message), g_text_format_path, fallback_rect, 0xFFFFFFFF);
        } else {
            // Placeholder for empty message
            D2D1_RECT_F placeholder_rect = D2D1::RectF(
                text_left + Theme::PADDING_SMALL, y,
                text_right - Theme::PADDING_SMALL, y + MESSAGE_LINE_HEIGHT
            );
            ctx.draw_text(L"(No commit message)", 19, g_text_format_path, placeholder_rect, 0x80FFFFFF);
        }

        ctx.pop_clip();

        // Scrollbar for message (if content exceeds visible height)
        if (message_content_height > visible_height + 1.0f) {
            float scrollbar_width = 4.0f;
            float scrollbar_x = text_right - scrollbar_width - 2.0f;
            float max_scroll = message_content_height - visible_height;
            if (max_scroll > 0.0f) {
                float thumb_height = fmaxf(20.0f, visible_height * (visible_height / message_content_height));
                float thumb_y = y + (message_scroll_y / max_scroll) * (visible_height - thumb_height);

                D2D1_ROUNDED_RECT thumb_rect = D2D1::RoundedRect(
                    D2D1::RectF(scrollbar_x, thumb_y, scrollbar_x + scrollbar_width, thumb_y + thumb_height),
                    scrollbar_width / 2.0f, scrollbar_width / 2.0f
                );
                ctx.brush->SetColor(color_from_argb(0x60FFFFFF));
                ctx.target->FillRoundedRectangle(thumb_rect, ctx.brush);
            }
        }
    }

    bool on_mouse_move(float x, float y) override {
        // Handle scrollbar dragging
        if (scrollbar_dragging) {
            float visible_height = message_visible_height > 0.0f ? message_visible_height : MESSAGE_LINE_HEIGHT;
            float max_scroll = message_content_height - visible_height;
            if (max_scroll > 0.0f) {
                // Convert mouse movement to scroll delta
                // The scrollbar thumb moves within (visible_height - thumb_height)
                // The scroll content moves within max_scroll
                float thumb_height = fmaxf(20.0f, visible_height * (visible_height / message_content_height));
                float track_height = visible_height - thumb_height;
                float scroll_ratio = max_scroll / track_height;

                float dy = y - scrollbar_drag_start_y;
                message_scroll_y = scrollbar_drag_start_scroll + dy * scroll_ratio;
                message_scroll_y = fmaxf(0.0f, fminf(message_scroll_y, max_scroll));
                set_dirty();
            }
            return true;
        }

        bool was_close_hovered = close_hovered;

        // Check close button hit (coordinates are relative to widget)
        float close_x = rect.width - Theme::PADDING - CLOSE_BUTTON_SIZE;
        float close_y = Theme::PADDING + (TITLE_LINE_HEIGHT - CLOSE_BUTTON_SIZE) / 2.0f;

        close_hovered = (x >= close_x && x < close_x + CLOSE_BUTTON_SIZE &&
                        y >= close_y && y < close_y + CLOSE_BUTTON_SIZE);

        if (was_close_hovered != close_hovered) {
            set_dirty();
        }

        return false;
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        if (scrollbar_dragging) {
            scrollbar_dragging = false;
            return true;
        }
        return false;
    }

    bool on_mouse_leave() override {
        if (close_hovered) {
            close_hovered = false;
            set_dirty();
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)button;

        // Check close button (coordinates are relative to widget)
        float close_x = rect.width - Theme::PADDING - CLOSE_BUTTON_SIZE;
        float close_y = Theme::PADDING + (TITLE_LINE_HEIGHT - CLOSE_BUTTON_SIZE) / 2.0f;

        if (x >= close_x && x < close_x + CLOSE_BUTTON_SIZE &&
            y >= close_y && y < close_y + CLOSE_BUTTON_SIZE) {
            if (on_close) {
                on_close(this, user_data);
            }
            return true;
        }

        // Check scrollbar hit (if scrollbar is visible)
        float visible_height = message_visible_height > 0.0f ? message_visible_height : MESSAGE_LINE_HEIGHT;
        if (message_content_height > visible_height + 1.0f) {
            float msg_y = Theme::PADDING + TITLE_LINE_HEIGHT + AUTHOR_LINE_HEIGHT + Theme::PADDING_SMALL;
            float text_right = rect.width - Theme::PADDING;
            float scrollbar_width = 4.0f;
            float scrollbar_x = text_right - scrollbar_width - 2.0f;

            // Check if click is in scrollbar track area
            if (x >= scrollbar_x - 4.0f && x <= scrollbar_x + scrollbar_width + 4.0f &&
                y >= msg_y && y <= msg_y + visible_height) {
                scrollbar_dragging = true;
                scrollbar_drag_start_y = y;
                scrollbar_drag_start_scroll = message_scroll_y;
                return true;
            }
        }

        return false;
    }

    bool on_mouse_wheel(float x, float y, float delta) override {
        (void)x; (void)y;

        // No scrolling if content fits in visible area
        if (message_content_height <= message_visible_height + 1.0f) {
            return false;
        }

        float max_scroll = message_content_height - message_visible_height;
        message_scroll_y -= delta * MESSAGE_LINE_HEIGHT * 3.0f;
        message_scroll_y = fmaxf(0.0f, fminf(message_scroll_y, max_scroll));
        set_dirty();
        return true;
    }
};
